-- Built-in registration sample estimates (exported from company 2144).
-- Re-run Scripts/Export_SystemEstimatesRegistrationSeed.ps1 to refresh.
SET NOCOUNT ON;
IF @companyId <= 0 OR @adminUserId <= 0 RETURN;
IF EXISTS (SELECT 1 FROM tb_estimate WHERE CompanyID = @companyId AND ISNULL(IsDeleted,0) = 0 AND Comments LIKE N'%Registration sample estimate (EST-0000299)%') RETURN;

DECLARE @customerId int, @contactId bigint, @deptId int, @addressId int, @statusId int;
DECLARE @digitalPressId bigint, @lithoPressId bigint, @largePressId bigint, @paperId bigint;
DECLARE @printSheetSizeId int, @jobSizeId int, @guillotineId bigint, @largeGuillotineId bigint, @taxId int;

SELECT TOP 1 @customerId = c.clientID, @contactId = ISNULL(ct.contactId,0), @deptId = ISNULL(d.DeptID,0), @addressId = ISNULL(NULLIF(c.AddressID,0), c.clientID)
FROM tb_client c
OUTER APPLY (SELECT TOP 1 contactId FROM tb_contact WHERE ClientID = c.clientID AND companyID = c.companyID AND ISNULL(isDelete,0)=0 ORDER BY CASE WHEN ISNULL(DefaultContact,0)=1 THEN 0 ELSE 1 END, contactId) ct
OUTER APPLY (SELECT TOP 1 DeptID FROM tb_Department WHERE CustomerID = c.clientID AND CompanyID = c.companyID AND ISNULL(IsDeleted,0)=0 ORDER BY DeptID) d
WHERE c.companyID = @companyId AND c.companytype = N'Customer' AND ISNULL(c.isdelete,0)=0
ORDER BY CASE WHEN LTRIM(RTRIM(c.clientname)) IN (N'Test Customer', N'Test%20Customer') THEN 0 ELSE 1 END, c.clientID;
IF @customerId IS NULL OR @customerId <= 0 RETURN;

SELECT TOP 1 @statusId = StatusID FROM tb_EstimateStatus WHERE companyid = @companyId AND ISNULL(IsDeleted,0)=0 AND ISNULL(Estimate,0)=1 ORDER BY ISNULL(EstimateDefault,0) DESC, StatusID;
SELECT @digitalPressId = (SELECT TOP 1 DigitalPressID FROM tb_DigitalPress WHERE CompanyID=@companyId AND ISNULL(IsDeleted,0)=0 ORDER BY ISNULL(IsDefaultPress,0) DESC, DigitalPressID);
SELECT @lithoPressId = (SELECT TOP 1 LithoPressID FROM tb_LithoPress WHERE CompanyID=@companyId AND ISNULL(IsDeleted,0)=0 ORDER BY ISNULL(IsDefaultPress,0) DESC, LithoPressID);
SELECT @largePressId = (SELECT TOP 1 PressID FROM tb_LargeFormatPress WHERE CompanyID=@companyId AND ISNULL(IsDeleted,0)=0 ORDER BY ISNULL(IsDefaultPress,0) DESC, PressID);
SELECT @paperId = (SELECT TOP 1 InventoryID FROM tb_inventory WHERE CompanyID=@companyId AND InventoryCode=N'PAPER-130' AND ISNULL(IsDeleted,0)=0);
SELECT @printSheetSizeId = (SELECT TOP 1 PaperSizeID FROM tb_papersize WHERE companyid=@companyId AND PaperSizeName=N'SRA3' AND ISNULL(IsDeleted,0)=0);
SELECT @jobSizeId = (SELECT TOP 1 PaperSizeID FROM tb_papersize WHERE companyid=@companyId AND PaperSizeName=N'A4' AND ISNULL(IsDeleted,0)=0);
SELECT @guillotineId = (SELECT TOP 1 GuillotineID FROM tb_Guillotine WHERE CompanyID=@companyId AND GuillotineName=N'Sample Guillotine' AND ISNULL(IsDeleted,0)=0);
SELECT @largeGuillotineId = (SELECT TOP 1 GuillotineID FROM tb_Guillotine WHERE CompanyID=@companyId AND GuillotineName=N'Sample Cutting Table' AND ISNULL(IsDeleted,0)=0);
SELECT @taxId = (SELECT TOP 1 TaxID FROM tb_taxrates WHERE CompanyID=@companyId AND ISNULL(IsDeleted,0)=0 ORDER BY TaxID);
IF @jobSizeId IS NULL OR @jobSizeId <= 0 SET @jobSizeId = @printSheetSizeId;
IF @largeGuillotineId IS NULL OR @largeGuillotineId <= 0 SET @largeGuillotineId = @guillotineId;
IF @largePressId IS NULL OR @largePressId <= 0 SET @largePressId = @lithoPressId;

