-- Ensure item detail rows exist (summary page QtyCount)
INSERT INTO tb_EstimateItemDetails (EstimateID, EstimateItemID, EstimateType, CreatedDate, IsDeleted)
SELECT ei.EstimateID, ei.EstimateItemID, ei.EstimateType, GETDATE(), 0
FROM tb_estimateitem ei
INNER JOIN tb_estimate e ON e.EstimateID = ei.EstimateID
WHERE e.CompanyID = @companyId AND ISNULL(ei.IsDeleted, 0) = 0
  AND e.Comments LIKE N'%Registration sample estimate (%'
  AND NOT EXISTS (SELECT 1 FROM tb_EstimateItemDetails d WHERE d.EstimateItemID = ei.EstimateItemID AND ISNULL(d.IsDeleted, 0) = 0);

UPDATE d SET
  d.Qty1 = CASE WHEN ISNULL(tpd.TotalQty1, 0) > 0 THEN CAST(tpd.TotalQty1 AS int) ELSE 1 END,
  d.Qty2 = CASE WHEN ISNULL(tpd.TotalQty2, 0) > 0 THEN CAST(tpd.TotalQty2 AS int) ELSE 0 END,
  d.Qty3 = CASE WHEN ISNULL(tpd.TotalQty3, 0) > 0 THEN CAST(tpd.TotalQty3 AS int) ELSE 0 END,
  d.Qty4 = CASE WHEN ISNULL(tpd.TotalQty4, 0) > 0 THEN CAST(tpd.TotalQty4 AS int) ELSE 0 END
FROM tb_EstimateItemDetails d
INNER JOIN tb_estimateitem ei ON ei.EstimateItemID = d.EstimateItemID
INNER JOIN tb_estimate e ON e.EstimateID = ei.EstimateID
LEFT JOIN tb_EstTotalPriceDetails tpd ON tpd.EstimateItemID = ei.EstimateItemID
WHERE e.CompanyID = @companyId AND ISNULL(d.IsDeleted, 0) = 0
  AND e.Comments LIKE N'%Registration sample estimate (%';

-- Assign estimate numbers from tenant counter
DECLARE @counter bigint, @num nvarchar(50), @prefix nvarchar(20) = N'EST-', @eid bigint;
DECLARE est_cursor CURSOR LOCAL FAST_FORWARD FOR
    SELECT EstimateID FROM tb_estimate
    WHERE CompanyID = @companyId AND ISNULL(IsDeleted,0)=0
        AND Comments LIKE N'%Registration sample estimate (EST-%'
        AND (EstimateNumber IS NULL OR LTRIM(RTRIM(EstimateNumber)) = N'')
    ORDER BY EstimateID;
OPEN est_cursor;
FETCH NEXT FROM est_cursor INTO @eid;
WHILE @@FETCH_STATUS = 0
BEGIN
    SELECT @counter = ISNULL(LastCounter,0)+1 FROM tb_lastCounter WHERE CompanyID=@companyId AND ModuleType=N'Estimate';
    IF @counter IS NULL BEGIN SET @counter=1; INSERT INTO tb_lastCounter (CompanyID,ModuleType,LastCounter) VALUES (@companyId,N'Estimate',@counter); END
    ELSE UPDATE tb_lastCounter SET LastCounter=@counter WHERE CompanyID=@companyId AND ModuleType=N'Estimate';
    SET @num = @prefix + SUBSTRING(CAST(10000000+@counter AS varchar(20)),2,20);
    UPDATE tb_estimate SET EstimateNumber=@num WHERE EstimateID=@eid;
    FETCH NEXT FROM est_cursor INTO @eid;
END
CLOSE est_cursor; DEALLOCATE est_cursor;
